import React, { useState } from 'react';

const App = () => {
  const [isDiscountApplied, setIsDiscountApplied] = useState(false);
  const regularPrice = 19.99;
  const salePrice = 9.99;

  const handleToggle = () => {
    setIsDiscountApplied(!isDiscountApplied);
  };

  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <div className="bg-[#B7D7CD] p-4 rounded-md shadow-md">
        <h2 className="text-2xl font-bold mb-2">Product Name</h2>
        <p className="text-lg mb-2">Regular Price: $19.99</p>
        <p className="text-lg mb-2">Sale Price: ${salePrice.toFixed(2)}</p>
        <button
          className="bg-[#C06C88] hover:bg-[#C06C88] hover:text-white text-white font-bold py-2 px-4 rounded-full"
          onClick={handleToggle}
        >
          Apply Discount
        </button>
      </div>
    </div>
  );
};

export default App;
